mapper.select:
SELECT id, order_no, user_id, total_amount, status, address_snapshot, payment_time, shipping_time, complete_time, cancel_time, create_time, update_time FROM orders WHERE user_id = #{userId}
AND status = #{status}
ORDER BY create_time DESC

mapper.update:
